import{_ as a,r as n,o as s,e as r,l as i,x as h,w as c,F as l,E as e,g as t}from"./app.a050b316.js";var d="/images/Chatwoot/how-it-works-1.png",g="/images/Chatwoot/how-it-works-2.png",w="/images/Chatwoot/how-it-works-3.png",m="/images/Chatwoot/how-it-works-4.gif",p="/images/Chatwoot/how-it-works-5.png",u="/images/Chatwoot/config-agents.png",f="/images/Chatwoot/config-inbox-1.png",_="/images/Chatwoot/config-inbox-2.png",b="/images/Chatwoot/get-team-id.png";const v={},C=e('<h1 id="chatwoot" tabindex="-1"><a class="header-anchor" href="#chatwoot" aria-hidden="true">#</a> Chatwoot</h1><p>When a user demands talking to a human agent, we can forward the conversation to the support system. Currently the open source system Chatwoot is the only support system.</p><h2 id="how-it-works" tabindex="-1"><a class="header-anchor" href="#how-it-works" aria-hidden="true">#</a> How It Works</h2><ol><li>When an end-user demands talking to a human agent.</li></ol><p><img src="'+d+'" alt="how-it-works-1"></p><ol start="2"><li>An agent will get notified when the conversation is assigned to him.</li></ol><p><img src="'+g+'" alt="how-it-works-2"></p><ol start="3"><li>The agent can view the history of the conversation and communicate with the end-user in conversation window.</li></ol><p><img src="'+w+'" alt="how-it-works-3"></p><ol start="4"><li>The agent can resolve the conversation when he is done with service.</li></ol><p><img src="'+m+'" alt="how-it-works-4"></p><ol start="5"><li>After the agent resolves the conversation, next time the end-user will start with interacting bot again.</li></ol><p><img src="'+p+'" alt="how-it-works-4"></p><h2 id="configuration" tabindex="-1"><a class="header-anchor" href="#configuration" aria-hidden="true">#</a> Configuration</h2><p>Now you can follow these steps to configure your account in Chatwoot.</p><h3 id="add-agents" tabindex="-1"><a class="header-anchor" href="#add-agents" aria-hidden="true">#</a> Add Agents</h3>',16),k=t("When you "),x=t("enable Chatwoot"),y=t(", we create a Chatwoot organization and add all the owners in your organization to it. The owners added to Chatwoot organization are called agents which are set as administrators by default."),A=e('<div class="custom-container tip"><p class="custom-container-title">How to Manage Owners in Your Organization?</p><ol><li>Log into Framely account and enter your organization.</li><li>Click <strong>Settings</strong> &gt; <strong>Internal Members</strong>. Now You can view all the onwers and members in your organization.</li><li>Click <strong>\xB7\xB7\xB7</strong> to set the internal member as owner / member, or to remove internal members.</li></ol></div><p>Once you log into <a href="https://chatwoot.naturali.io/" target="_blank" rel="noopener noreferrer">Chatwoot</a>, you can click <strong>Settings</strong> &gt; <strong>Agents</strong> &gt; <strong>Add Agent</strong> and follow the instructions. Agents you add will receive an email with a confirmation link to activate their account, after which they can access Chatwoot and respond to messages sent by end-users.</p><p><img src="'+u+'" alt="config-agents"></p><div class="custom-container danger"><p class="custom-container-title">DANGER</p><p>The role of BotAgent1 should always be administrator. Otherwise, agents can not receive messages sent by end-users.</p></div><h3 id="set-up-inbox" tabindex="-1"><a class="header-anchor" href="#set-up-inbox" aria-hidden="true">#</a> Set Up Inbox</h3><p>When you enable Chatwoot in a chatbot, we will create an inbox named after the chatbot and connect the inbox to the chatbot. When you deploy the chatbot to a channel and end-users send messages to the chatbot through that channel, you can get the conversation in the corresponding inbox.</p><p>Follow these steps to add an agent to the inbox so when it&#39;s needed agents can carry on the conversation.</p><ol><li>Click <strong>Inboxes</strong> &gt; <strong>Settings</strong></li></ol><p><img src="'+f+'" alt="config-inbox-1"></p><ol start="2"><li>In <strong>Collaborators</strong> field, add agents to the inbox and click <strong>Update</strong> to save changes.</li></ol><p><img src="'+_+'" alt="config-inbox-2"></p><h3 id="add-teams" tabindex="-1"><a class="header-anchor" href="#add-teams" aria-hidden="true">#</a> Add Teams</h3><p>When the conversation is assigned to a team, the agents in the team can carry on the conversation. See <a href="https://www.chatwoot.com/docs/user-guide/add-teams-settings" target="_blank" rel="noopener noreferrer">Chatwoot - Add Teams</a> to learn how to add teams.</p><h2 id="how-to-get-team-id" tabindex="-1"><a class="header-anchor" href="#how-to-get-team-id" aria-hidden="true">#</a> How to Get Team Id</h2><p>In the <strong>Conversations</strong> field, select a team. The last number in current url is the id of this team. As shown, the id of <strong>team a</strong> is 47.</p><p><img src="'+b+'" alt="get-team-id"></p>',16);function T(I,N){const o=n("RouterLink");return s(),r(l,null,[C,i("p",null,[k,h(o,{to:"/reference/support/overview.html#enable-support"},{default:c(()=>[x]),_:1}),y]),A],64)}var z=a(v,[["render",T],["__file","Chatwoot.html.vue"]]);export{z as default};
